# Test with abstract class property
from abc import ABC, abstractmethod

class B(ABC):
    @classmethod
    @property
    @abstractmethod
    def f(cls):
        '''Abstract class property.'''
        return 'abstract'

    @classmethod
    @property
    def g(cls):
        '''Regular class property.'''
        return 'regular'

members = get_class_members(B, [], safe_getattr)
print('Members of B:')
for name in ['f', 'g']:
    if name in members:
        member = members[name]
        print(f'  {name}:')
        print(f'    object type: {type(member.object).__name__}')
        print(f'    __doc__: {member.object.__doc__}')
        print(f'    isproperty: {isproperty(member.object)}')
        if hasattr(member.object, '__isabstractmethod__'):
            print(f'    __isabstractmethod__: {member.object.__isabstractmethod__}')
        elif hasattr(member.object.__func__, '__isabstractmethod__'):
            print(f'    __func__.__isabstractmethod__: {member.object.__func__.__isabstractmethod__}')
        print()
"
